# 测试IMA API连接
$ApiKey = "xeLf6p2d85BSJnMuYfrFUbQmPT08tUKVEe/fZGsvA5LLVrUKy13zuh3XSWkCnW3CXKKUqG473w=="
$ClientId = "e49eed7e89020c8baec3358d9e9732a5"

Write-Host "测试IMA API连接..." -ForegroundColor Cyan
Write-Host "API Key: $($ApiKey.Substring(0, 10))..." -ForegroundColor Gray
Write-Host "Client ID: $ClientId" -ForegroundColor Gray

# 尝试调用IMA API
$Endpoint = "https://ima.qq.com/api/v1/chat/completions"

$Headers = @{
    "Authorization" = "Bearer $ApiKey"
    "Content-Type" = "application/json"
    "X-Client-Id" = $ClientId
}

$Body = @{
    model = "ima-pro"
    messages = @(
        @{
            role = "user"
            content = "你好，请简单介绍一下你自己"
        }
    )
} | ConvertTo-Json -Depth 10

try {
    Write-Host "发送测试请求..." -ForegroundColor Yellow
    $Response = Invoke-RestMethod -Uri $Endpoint -Method Post -Headers $Headers -Body $Body -TimeoutSec 30

    Write-Host "`n✅ 连接成功！" -ForegroundColor Green
    Write-Host "IMA回复:" -ForegroundColor White
    if ($Response.choices -and $Response.choices[0].message) {
        Write-Host $Response.choices[0].message.content -ForegroundColor White
    } else {
        Write-Host "响应格式:" -ForegroundColor Yellow
        $Response | ConvertTo-Json -Depth 10 | Write-Host
    }
}
catch {
    Write-Host "`n❌ 连接失败:" -ForegroundColor Red
    Write-Host "错误信息: $_" -ForegroundColor Red

    if ($_.Exception.Response) {
        $StatusCode = $_.Exception.Response.StatusCode.value__
        $StatusDescription = $_.Exception.Response.StatusDescription
        Write-Host "HTTP状态码: $StatusCode ($StatusDescription)" -ForegroundColor Red

        try {
            $ErrorStream = $_.Exception.Response.GetResponseStream()
            $Reader = New-Object System.IO.StreamReader($ErrorStream)
            $ErrorBody = $Reader.ReadToEnd()
            $Reader.Close()
            Write-Host "错误详情:" -ForegroundColor Red
            $ErrorBody | Write-Host
        }
        catch {
            Write-Host "无法读取错误详情" -ForegroundColor Yellow
        }
    }

    Write-Host "`n可能的解决方案:" -ForegroundColor Cyan
    Write-Host "1. 检查API Key和Client ID是否正确" -ForegroundColor Gray
    Write-Host "2. 确认账号有足够的余额" -ForegroundColor Gray
    Write-Host "3. 检查网络连接" -ForegroundColor Gray
    Write-Host "4. 确认API权限" -ForegroundColor Gray
}

